import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'your-vex-key' });

async function filterMemoryResults(results: MemoryRecord[]): Promise<MemoryRecord[]> {
  const verified = await vex.verify({
    input: 'research_context_retrieval',
    output: results.map(r => r.text),
    verifications: ['claim_accuracy', 'bias_detection', 'recency_checks'],
    risk_profile: 'medium'
  });

  return verified.valid ? results : [];
}

